namespace sv_4330742e381b431ab6239855365c6a93.Services;

public class AppointmentService
{
    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(new List<string>
        {
            "Dr. Smith",
            "Dr. Johnson",
            "Dr. Williams",
            "Dr. Patel"
        });
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date)
    {
        return Task.FromResult(new List<string>
        {
            "9:00 AM",
            "10:00 AM",
            "11:00 AM",
            "1:00 PM",
            "2:00 PM",
            "3:00 PM"
        });
    }

    /// <summary>
    /// Validates patient/appointment data server-side.
    /// Returns a dictionary of field name -> error message for any failures.
    /// </summary>
    public Task<Dictionary<string, string>> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var errors = new Dictionary<string, string>();

        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors["Email"] = "Account has outstanding balance";
        }

        if (insuranceProvider == "None" && doctor == "Dr. Smith")
        {
            errors["Doctor"] = "Selected doctor does not accept self-pay patients";
        }

        if (timeSlot == "10:00 AM")
        {
            errors["TimeSlot"] = "This slot is no longer available";
        }

        return Task.FromResult(errors);
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_4330742e381b431ab6239855365c6a93.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h3>Book a Medical Appointment</h3>

<EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="bookAppointment">
    <DataAnnotationsValidator />

    @* ── STEP 1: Patient Information ── *@
    <fieldset>
        <legend>Patient Information</legend>

        <div class="mb-3">
            <label class="form-label" for="patientName">Patient Name</label>
            <InputText id="patientName" class="form-control" @bind-Value="Model.PatientName" />
            <ValidationMessage For="() => Model.PatientName" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="email">Email</label>
            <InputText id="email" class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="() => Model.Email" />
            @if (serverErrors.ContainsKey("Email"))
            {
                <div class="validation-message">@serverErrors["Email"]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label" for="phone">Phone</label>
            <InputText id="phone" class="form-control" @bind-Value="Model.Phone" />
            <ValidationMessage For="() => Model.Phone" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="insurance">Insurance Provider</label>
            <InputSelect id="insurance" class="form-select" @bind-Value="Model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => Model.InsuranceProvider" />
        </div>
    </fieldset>

    @if (!showStep2)
    {
        <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
            Next
        </button>
    }

    @* ── STEP 2: Appointment Details (visible after step 1 validates) ── *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Appointment Details</legend>

            <div class="mb-3">
                <label class="form-label" for="doctor">Preferred Doctor</label>
                <InputSelect id="doctor" class="form-select" @bind-Value="Model.Doctor"
                             @bind-Value:after="OnDoctorOrDateChanged">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.Doctor" />
                @if (serverErrors.ContainsKey("Doctor"))
                {
                    <div class="validation-message">@serverErrors["Doctor"]</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="date">Date</label>
                <InputDate id="date" class="form-control" @bind-Value="Model.AppointmentDate"
                           @bind-Value:after="OnDoctorOrDateChanged" />
                <ValidationMessage For="() => Model.AppointmentDate" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="timeSlot">Time Slot</label>
                <InputSelect id="timeSlot" class="form-select" @bind-Value="Model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in timeSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.TimeSlot" />
                @if (serverErrors.ContainsKey("TimeSlot"))
                {
                    <div class="validation-message">@serverErrors["TimeSlot"]</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="reason">Reason for Visit</label>
                <InputTextArea id="reason" class="form-control" @bind-Value="Model.ReasonForVisit" rows="3" />
                <ValidationMessage For="() => Model.ReasonForVisit" />
            </div>

            <div class="d-flex gap-2">
                <button type="button" class="btn btn-secondary" @onclick="BackToStep1">
                    Back
                </button>
                <button type="button" class="btn btn-outline-primary" @onclick="CheckAvailability"
                        disabled="@isChecking">
                    @(isChecking ? "Checking…" : "Check Availability")
                </button>
                <button type="submit" class="btn btn-primary" disabled="@(!availabilityChecked)">
                    Book Appointment
                </button>
            </div>
        </fieldset>
    }
</EditForm>

@if (submitted)
{
    <div class="alert alert-success mt-4">
        Appointment booked successfully!
    </div>
}

@code {
    private AppointmentFormModel Model { get; set; } = new();
    private List<string> doctors = new();
    private List<string> timeSlots = new();
    private Dictionary<string, string> serverErrors = new();
    private bool showStep2;
    private bool isChecking;
    private bool availabilityChecked;
    private bool submitted;

    private EditContext? editContext;

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(Model);
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        editContext = new EditContext(Model);
        // Validate only step-1 fields
        var isValid = true;
        var validator = new System.ComponentModel.DataAnnotations.ValidationContext(Model);
        var results = new List<System.ComponentModel.DataAnnotations.ValidationResult>();
        System.ComponentModel.DataAnnotations.Validator.TryValidateObject(Model, validator, results, true);

        var step1Fields = new HashSet<string> { "PatientName", "Email", "Phone", "InsuranceProvider" };
        var step1Errors = results.Where(r => r.MemberNames.Any(m => step1Fields.Contains(m))).ToList();

        if (step1Errors.Count == 0)
        {
            showStep2 = true;
        }
        else
        {
            // Trigger full validation so messages show up via EditContext
            editContext.Validate();
        }
    }

    private void BackToStep1()
    {
        showStep2 = false;
        serverErrors.Clear();
        availabilityChecked = false;
    }

    private async Task OnDoctorOrDateChanged()
    {
        availabilityChecked = false;
        serverErrors.Remove("Doctor");
        serverErrors.Remove("TimeSlot");
        Model.TimeSlot = string.Empty;

        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
        {
            timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                Model.Doctor,
                DateOnly.FromDateTime(Model.AppointmentDate.Value));
        }
    }

    private async Task CheckAvailability()
    {
        serverErrors.Clear();
        availabilityChecked = false;

        // Client-side validation of step-2 fields first
        editContext = new EditContext(Model);
        if (!editContext.Validate())
        {
            return;
        }

        isChecking = true;

        try
        {
            var errors = await AppointmentService.ValidatePatientAsync(
                Model.Email,
                Model.InsuranceProvider,
                Model.Doctor,
                Model.TimeSlot);

            if (errors.Count > 0)
            {
                serverErrors = errors;
            }
            else
            {
                availabilityChecked = true;
            }
        }
        finally
        {
            isChecking = false;
        }
    }

    private void HandleSubmit()
    {
        if (!availabilityChecked)
            return;

        submitted = true;
    }
}

using System.ComponentModel.DataAnnotations;

namespace sv_4330742e381b431ab6239855365c6a93.Components.Pages;

public class AppointmentFormModel
{
    // Step 1
    [Required(ErrorMessage = "Patient name is required.")]
    public string PatientName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Invalid email format.")]
    public string Email { get; set; } = string.Empty;

    [Required(ErrorMessage = "Phone is required.")]
    public string Phone { get; set; } = string.Empty;

    [Required(ErrorMessage = "Insurance provider is required.")]
    public string InsuranceProvider { get; set; } = string.Empty;

    // Step 2
    [Required(ErrorMessage = "Please select a doctor.")]
    public string Doctor { get; set; } = string.Empty;

    [Required(ErrorMessage = "Date is required.")]
    [FutureDate(ErrorMessage = "Date must be in the future.")]
    public DateTime? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Please select a time slot.")]
    public string TimeSlot { get; set; } = string.Empty;

    [Required(ErrorMessage = "Reason for visit is required.")]
    [MaxLength(500, ErrorMessage = "Reason must be 500 characters or fewer.")]
    public string ReasonForVisit { get; set; } = string.Empty;
}

public class FutureDateAttribute : ValidationAttribute
{
    protected override ValidationResult? IsValid(object? value, ValidationContext validationContext)
    {
        if (value is DateTime date && date.Date <= DateTime.Today)
        {
            return new ValidationResult(ErrorMessage, new[] { validationContext.MemberName! });
        }
        return ValidationResult.Success;
    }
}

